function SurveyComponent() {

  const [userInfo, setUserInfo] = useState();

  useEffect(() => {
    const fetchInfo = async () => {

      try {
        const response = await axios.get('http://localhost:8080/api/user-info', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (response.status === 200) {
          setUserInfo(response.data.id);
          return;
        }

      } catch (error) {

        if (error.response && error.response.status === 401) {
          localStorage.removeItem('token');
          navigate('/login');
          return;
        }
        setMessagePopup(error.response?.data?.msg || error.message);
        setButtonPopup(true);
      }
    };
    fetchInfo();
  }, []);

  const survey = new Model(json);
  survey.applyTheme(themeJson);

  const ENDPOINT_URL = "http://localhost:8080/api/responses";

  async function submitSurveyData(data) {
    const token = localStorage.getItem('token');
    try {
      const response = await axios.post(ENDPOINT_URL, data, {
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}` // Aggiungi il token nell'intestazione Authorization
        }
      });

      console.log("Survey data saved:", response.data);
    } catch (error) {
      console.error("Error saving survey data:", error);
      if (error.response) {
        // Il server ha risposto con uno stato diverso da 2xx
        console.error("Server responded with:", error.response.status, error.response.data);
      } else if (error.request) {
        // La richiesta è stata fatta, ma non è stata ricevuta nessuna risposta
        console.error("No response received:", error.request);
      } else {
        // Qualcosa è andato storto durante la configurazione della richiesta
        console.error("Error setting up request:", error.message);
      }
    }
  }



  // Funzione per salvare i dati del survey ad ogni modifica
  function saveSurveyData(survey) {
    const data = {
      surveyId: userInfo,  // Supponendo che il surveyId sia parte del survey data
      //userId: survey.getValue("userId") || "1",  // Ottieni o imposta userId
      pageNo: survey.currentPageNo,
      surveyData: survey.data
    };
    submitSurveyData(data);
  }

  // Imposta i listener per gli eventi del survey
  useEffect(() => {
    survey.onValueChanged.add((sender, options) => {
      saveSurveyData(sender);
    });

    survey.onCurrentPageChanged.add((sender, options) => {
      saveSurveyData(sender);
    });

    survey.onComplete.add((sender) => {
      saveSurveyData(sender);
    });
  }, [survey]);

  return <Survey model={survey} />;
}

export default SurveyComponent;

